import json
from datetime import datetime
from pathlib import Path
from typing import Dict, List

IGNORE_DIRS = {".git", ".venv", "venv", "__pycache__", "output", ".md", "__init__.py", "planilhas", ".uv-cache",".vscode"}


def is_ignored(path: Path) -> bool:
    return any(part in IGNORE_DIRS for part in path.parts)


def read_text(path: Path) -> str:
    return path.read_text(encoding="utf-8", errors="ignore")


def to_module_name(rel_path: str) -> str:
    module = rel_path.replace("/", ".").removesuffix(".py")
    if module.endswith(".__init__"):
        module = module[: -len(".__init__")]
    return module


def collect_source_files(root: Path) -> List[Dict[str, str]]:
    files: List[Dict[str, str]] = []
    for p in sorted(root.rglob("*")):
        if p.is_file() and not is_ignored(p):
            if p.suffix not in {".py", ".sql"}:
                continue
            rel = p.relative_to(root).as_posix()
            entry: Dict[str, str] = {
                "path": rel,
                "content": read_text(p),
            }
            if p.suffix == ".py":
                entry["module"] = to_module_name(rel)
            files.append(entry)
    return files


def build_index(files: List[Dict[str, str]]) -> List[str]:
    return [f["path"] for f in files]


def build_top_level(files: List[Dict[str, str]]) -> Dict[str, List[str]]:
    dirs = set()
    root_files = set()
    for f in files:
        path = f["path"]
        if "/" in path:
            dirs.add(path.split("/", 1)[0])
        else:
            root_files.add(path)
    return {
        "dirs": sorted(dirs),
        "files": sorted(root_files),
    }


def build_dump(root: Path) -> Dict[str, object]:
    files = collect_source_files(root)
    return {
        "schema_version": "1.2",
        "generated_at": datetime.now().isoformat(timespec="seconds"),
        "root": root.name,
        "description": "Dump do source code Python (.py) e SQL (.sql) com paths relativos.",
        "context": {
            "notes": [
                "Arquivos que nao sao .py ou .sql foram excluidos.",
                "Caminhos sao relativos a raiz do projeto.",
                "O campo module existe apenas para arquivos .py.",
            ]
        },
        "summary": {
            "file_count": len(files),
        },
        "layout": {
            "top_level": build_top_level(files),
        },
        "file_index": build_index(files),
        "files": files,
    }


def main() -> None:
    today = datetime.now().strftime("%Y.%m.%d")
    base = Path(__file__).parents[1]
    dump = build_dump(base)
    out_file = base / f"dump_{today}.json"
    out_file.write_text(
        json.dumps(dump, ensure_ascii=False, indent=2),
        encoding="utf-8",
    )
    size_kb = out_file.stat().st_size // 1024
    print(f"Arquivo criado: {out_file} ({size_kb} KB)")


if __name__ == "__main__":
    main()
